66|                    btn.textContent = 'Processing...';
67|
68|                    var reset = function () {
69|                        checkoutBtns.forEach(function (b) { b.style.pointerEvents = ''; b.style.opacity = ''; });
70|                        btn.textContent = label;
71|                    };
72|
73|                    fetch(amcCheckout.restUrl, {
74|                        method: 'POST',
75|                        headers: { 'Content-Type': 'application/json', 'X-WP-Nonce': amcCheckout.nonce },
76|                        body: JSON.stringify({ product: amcCheckout.product })
77|                    })
78|                        .then(function (r) { return r.json(); })
79|                        .then(function (data) {
80|                            if (data && data.url) {
81|                                window.location.href = data.url;
82|                            } else {
83|                                alert((data && data.message) || 'Something went wrong. Please try again.');
84|                                reset();
85|                            }
86|                        })
87|                        .catch(function () {
88|                            alert('Something went wrong. Please try again.');
89|                            reset();
90|                        });
91|                });
92|            });
93|        }
