95|        /* Copy-to-clipboard buttons (referral link, etc.) */
96|        document.querySelectorAll('.amc-copy-btn').forEach(function (btn) {
97|            btn.addEventListener('click', function () {
98|                var input = document.querySelector(btn.getAttribute('data-target'));
99|                if (!input) {
100|                    return;
101|                }
102|                input.select();
103|                input.setSelectionRange(0, 99999);
104|                var done = function () {
105|                    var original = btn.innerHTML;
